/* ------------------------------------------------------------------ */
/*  Metadata + SEO                                                     */
/* ------------------------------------------------------------------ */

function clampMeta(s: string, max = 155) {
  const clean = s.replace(/\s+/g, " ").trim();
  if (clean.length <= max) return clean;
  const cut = clean.slice(0, max - 1);
  const last = cut.lastIndexOf(".");
  return last > 80 ? cut.slice(0, last + 1) : cut.trimEnd() + "…";
}

export async function generateMetadata({
  params,
}: {
  params: Promise<{ locale: string; slug: string }>;
}): Promise<Metadata> {
  const { slug } = await params;
  const house = getHouse(slug.toLowerCase());
  if (!house) return {};

  const titreCourt = house.titreCourt ?? `Maison ${toRoman(house.numero)}`;
  // ✅ Ahrefs IndexNow rewrite — formulation plus complète (signification + interprétation).
  const title = `${titreCourt} en astrologie, signification & interprétation`;

  const arena = house.niveauLecture?.arena?.trim();
  const motsCles = (house.niveauLecture?.motsCles ?? []).slice(0, 3);
  const principaux = (house.domaines?.principaux ?? []).slice(0, 4);

  const description = clampMeta(
    `${titreCourt} (${house.nom}) : sens et interprétation. ` +
      (house.type ? `Maison ${house.type}. ` : "") +
      (arena ? `Thème : ${arena}. ` : "") +
      (motsCles.length ? `Mots-clés : ${motsCles.join(", ")}. ` : "") +
      (principaux.length ? `Domaines : ${principaux.join(", ")}. ` : "") +
      "Découvrez les significations traditionnelles et modernes.",
    155
  );

  // ✅ Suppression du champ `keywords` — Google ignore meta-keywords depuis 2009
  //    et leur présence envoie un signal "SEO d'il y a 15 ans". Audit 31/05/2026.

  return {
    ...buildMeta({
      title,
      description,
      canonicalPath: `/maisons/${house.slug}`,
      type: "article",
      ogImage: `/images/maisons/${toRoman(house.numero)}.webp`,
    }),
    // ✅ Ahrefs "title too long" fix — on retire le suffixe " — Astro Cours"
    //    pour rester ≤ 60 chars (sinon 71 chars avec template).
    title: { absolute: title },
  };
}

/* ------------------------------------------------------------------ */
/*  Schema.org JSON-LD                                                 */
/* ------------------------------------------------------------------ */

function buildJsonLd(house: typeof HOUSES[number]) {
  const titreCourt = house.titreCourt ?? `Maison ${toRoman(house.numero)}`;
  const url = absoluteUrl(`/maisons/${house.slug}`);

  return [{
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Article",
        headline: `${titreCourt} — ${house.nom}`,
        description:
          house.niveauLecture?.fonction ??
          `Étude approfondie de la ${titreCourt} en astrologie.`,
        url,
        image: absoluteUrl(`/images/maisons/hero/${toRoman(house.numero)}.webp`),
        author: AUTHOR_PERSON,
        publisher: PUBLISHER_ORG,
        datePublished: "2026-04-09T12:00:00Z",
        // ✅ Audit 31/05/2026 — dateModified dynamique sur le champ `updated` du JSON
        dateModified: house.updated
          ? `${house.updated}T12:00:00Z`
          : "2026-05-31T12:00:00Z",
        inLanguage: "fr",
        mainEntityOfPage: url,
      },
      buildCourseNode({
        path: `/maisons/${house.slug}`,
        name: `${titreCourt} (${house.nom}) — Signification et interprétation`,
        description: house.niveauLecture?.fonction ?? `Étude approfondie de la ${titreCourt} en astrologie.`,
        image: `/images/maisons/hero/${toRoman(house.numero)}.webp`,
        teaches: `Comprendre le rôle de la ${titreCourt} dans un thème natal`,
        topicName: `${titreCourt} — ${house.nom}`,
      }),
      {
        "@type": "BreadcrumbList",
        itemListElement: buildBreadcrumbs(house).map((crumb, i) => ({
          "@type": "ListItem",
          position: i + 1,
          name: crumb.name,
          item: absoluteUrl(crumb.href),
        })),
      },
      ...(house.faq && house.faq.length > 0
        ? [
            {
              "@type": "FAQPage",
              mainEntity: house.faq.map((f) => ({
                "@type": "Question",
                name: f.question,
                acceptedAnswer: { "@type": "Answer", text: f.reponse },
              })),
            },
          ]
        : []),
    ],
  }];
}

/* ------------------------------------------------------------------ */
/*  Dynamic TOC builder                                                */
/* ------------------------------------------------------------------ */

function buildTocSections(house: typeof HOUSES[number]) {
  const sections: Array<{ id: string; label: string }> = [];
  const push = (label: string) => sections.push({ id: sectionId(label), label });

  if (has(house.niveauLecture?.fonction)) push("Fonction");
  if (has(house.significationTraditionnelle)) push("Signification traditionnelle");
  if (has(house.conceptionModerne)) push("Conception moderne");
  if (has(house.niveauLecture?.questions)) push("Questions clés");
  if (has(house.domaines?.principaux) || has(house.domaines?.secondaires)) push("Domaines");
  if (has(house.polarites?.forces) || has(house.polarites?.ombres)) push("Repères");
  if (has(house.axeAnalyse)) push("Axe");
  if (has(house.triangle) || has(house.carre)) push("Triangle et Carré");
  if (has(house.pedagogie?.aRetenir)) push("Pédagogie");
  if (has(house.pratique?.phrasesCles)) push("Pratique");
  // ✅ Audit 31/05/2026 — nouvelles sections enrichies
  if (has(house.vieQuotidienne)) push("Au quotidien");
  if (has(house.carriere)) push("Carrière et argent");
  if (has(house.transitsNotables)) push("Transits notables");
  if (has(house.exercicePratique)) push("Exercice approfondi");
  if (has(house.personnagesEmblematiques)) push("Personnages emblématiques");
  push("Planètes dans cette maison");

  if (has(house.faq))
    sections.push({ id: "faq", label: "FAQ" });

  return sections;
}

